class APIGatewayServicer:
    """
    gRPC servicer that acts as an API gateway.
    Receives requests, builds metadata, forwards to backends,
    and sets trailing metadata on the response.
    """

    def __init__(self, backend_targets: Dict[str, str]):
        """
        Args:
            backend_targets: Mapping of service names to gRPC targets.
                e.g., {"user-service": "localhost:50052", "order-service": "localhost:50053"}
        """
        self.backend_targets = backend_targets
        self.clients: Dict[str, BackendServiceClient] = {}

        for service_name, target in backend_targets.items():
            self.clients[service_name] = BackendServiceClient(target=target)

    def ForwardRequest(self, request_data: dict, context):
        """
        Gateway endpoint that forwards requests to backend services.
        Demonstrates building metadata and setting trailing metadata.
        """
        # Extract incoming metadata from the caller
        incoming_metadata = dict(context.invocation_metadata())
        print(f"\n[APIGateway] Incoming metadata from caller:")
        for key, value in incoming_metadata.items():
            print(f"  {key}: {value}")

        # Determine target backend service
        target_service = request_data.get("target_service", "user-service")
        if target_service not in self.clients:
            context.set_code(grpc.StatusCode.NOT_FOUND)
            context.set_details(f"Backend service '{target_service}' not found")
            return {}

        # Build HTTP request from the incoming data
        http_request = HTTPRequest(
            method=request_data.get("method", "GET"),
            path=request_data.get("path", "/"),
            headers=incoming_metadata,
            body=request_data.get("body"),
            query_params=request_data.get("query_params", {}),
        )

        # Additional user-provided metadata
        user_metadata = request_data.get("custom_metadata", {})

        # Forward to backend
        client = self.clients[target_service]
        response = client.forward_unary_request(http_request, user_metadata)

        # Set trailing metadata on the gateway response
        gateway_trailing_metadata = [
            ("x-gateway-status", str(response.status_code)),
            ("x-gateway-backend", target_service),
            ("x-gateway-backend-target", self.backend_targets[target_service]),
        ]

        # Include any trailing metadata from the backend response
        for key, value in response.trailing_metadata.items():
            gateway_trailing_metadata.append((f"x-upstream-{key}", value))

        context.set_trailing_metadata(gateway_trailing_metadata)
        print(f"\n[APIGateway] Set trailing metadata: {gateway_trailing_metadata}")

        return response

    def close_all(self):
        """Close all backend client connections."""
        for client in self.clients.values():
            client.close()


