        """Intercept unary calls to inject metadata."""
        # Create new metadata combining defaults with call-specific metadata
        existing_metadata = list(client_call_details.metadata or [])
        combined_metadata = MetadataBuilder.merge_metadata(
            self.default_metadata, existing_metadata
        )

        # Create new client call details with updated metadata
        new_details = _ClientCallDetails(
            method=client_call_details.method,
            timeout=client_call_details.timeout,
            metadata=combined_metadata,
            credentials=client_call_details.credentials,
            wait_for_ready=client_call_details.wait_for_ready,
            compression=client_call_details.compression,
        )

        print(f"[Interceptor] Forwarding call with {len(combined_metadata)} metadata entries")
        return continuation(new_details, request)


